package jetbrains.mps.lang.test.junit5;

/*Generated by MPS */

import jetbrains.mps.lang.test.launcher.WorkerCallback;
import jetbrains.mps.tool.common.Script;
import jetbrains.mps.tool.environment.Environment;
import jetbrains.mps.project.Project;
import jetbrains.mps.baseLanguage.unitTest.platform.TestSessionConfig;
import jetbrains.mps.baseLanguage.unitTest.platform.TestSession;
import jetbrains.mps.baseLanguage.unitTest.platform.TestPlatform;
import org.junit.platform.launcher.TestExecutionListener;
import org.junit.platform.commons.PreconditionViolationException;
import java.util.List;
import java.util.ArrayList;
import org.jetbrains.mps.openapi.model.SNode;
import org.jetbrains.mps.openapi.module.SRepository;
import jetbrains.mps.smodel.MPSModuleRepository;
import jetbrains.mps.smodel.ModelAccessHelper;
import org.jetbrains.mps.openapi.persistence.PersistenceFacade;
import jetbrains.mps.persistence.PersistenceRegistry;
import org.jetbrains.mps.openapi.module.SModule;
import jetbrains.mps.internal.collections.runtime.ListSequence;
import jetbrains.mps.module.ReloadableModule;
import jetbrains.mps.baseLanguage.unitTest.platform.JUnitPlatform;
import java.io.File;

public class ScriptJUnit5Launcher extends AbstractJUnit5Launcher {

  public static final String HALT_ON_FAILURE = "launchtests.haltonfailure";
  public static final String TEST_REPORTS_DIR = "launchtests.testReportsDir";

  private final WorkerCallback myWorkerCallback;
  private final Script myWhatToDo;

  public ScriptJUnit5Launcher(Script whatToDo, Environment environment, WorkerCallback callback) {
    super(environment);
    this.myWhatToDo = whatToDo;
    this.myWorkerCallback = callback;
  }

  @Override
  public int launchTests() {
    Project project = myEnvironment.createProject(new ModuleFilesListProjectStrategy(myWhatToDo.getModules()));
    FailureDetector failureDetector = new FailureDetector();

    TestSessionConfig sessionConfig = new TestSessionConfig().withAccessory(Environment.class, myEnvironment);
    TestSession testSession = TestPlatform.getInstance().openSession(sessionConfig);
    try {
      launchTests(project, failureDetector);
    } finally {
      TestPlatform.getInstance().closeSession(testSession);
    }

    myEnvironment.closeProject(project);
    myEnvironment.dispose();

    if (isHaltOnFailure() && failureDetector.hasFailures()) {
      failureDetector.flushErrors(myWorkerCallback);
      myWorkerCallback.failBuild();
    }

    return failureDetector.failuresCount();
  }

  protected void launchTests(Project project, TestExecutionListener executionListener) throws PreconditionViolationException {
    List<Class<?>> testClasses = collectTestClasses(project);

    ClassLoader contextClassLoader = Thread.currentThread().getContextClassLoader();
    try {
      Thread.currentThread().setContextClassLoader(testModuleContextClassLoader(project));
      launchTests(testClasses, executionListener);

    } finally {
      Thread.currentThread().setContextClassLoader(contextClassLoader);
    }
  }

  private List<Class<?>> collectTestClasses(final Project project) {
    final List<Class<?>> testClasses = new ArrayList<>();
    final TestDiscoveryVisitor visitor = new TestDiscoveryVisitor() {
      @Override
      public void visitTestRoot(SNode testRootNode, String testClassName, ClassLoader moduleClassLoader) {
        try {
          testClasses.add(moduleClassLoader.loadClass(testClassName));

        } catch (ClassNotFoundException e) {
          myWorkerCallback.error("error building test suite", e);
        }
      }
    };

    project.getModelAccess().runReadAction(() -> {

      new TestDiscovery(visitor).surveyModules(project.getProjectModules());

    });

    return testClasses;
  }

  private ClassLoader testModuleContextClassLoader(final Project project) {
    final SRepository repo = myEnvironment.getPlatform().findComponent(MPSModuleRepository.class);
    return new ModelAccessHelper(repo).runReadAction(() -> {
      final PersistenceFacade pf = myEnvironment.getPlatform().findComponent(PersistenceRegistry.class);
      for (SModule testModule : ListSequence.fromList(project.getProjectModules())) {
        if (testModule instanceof ReloadableModule) {
          return ((ReloadableModule) testModule).getClassLoader();
        }
      }
      SModule junit5Module = pf.createModuleReference(JUnitPlatform.JUNIT5_LIBS_MODULE_REF).resolve(repo);
      if (junit5Module instanceof ReloadableModule) {
        return ((ReloadableModule) junit5Module).getClassLoader();
      }
      // if nothing works
      return Thread.currentThread().getContextClassLoader();
    });
  }

  private boolean isHaltOnFailure() {
    String property = myWhatToDo.getProperty(HALT_ON_FAILURE);
    return (property != null ? Boolean.valueOf(property) : false);
  }

  @Override
  protected File getTestReportsDir() {
    String property = myWhatToDo.getProperty(TEST_REPORTS_DIR);
    if (property == null) {
      return null;
    }
    File dir = new File(property);
    if (!(dir.exists())) {
      if (!(dir.mkdirs())) {
        myWorkerCallback.error("could not create directory for test reports: " + dir.getAbsolutePath());
        return null;
      }
    }
    if (!(dir.isDirectory())) {
      myWorkerCallback.error("not a directory: " + dir.getAbsolutePath());
      return null;
    }
    return dir;
  }

  @Override
  protected boolean isRunningOnTeamCity() {
    return myWhatToDo.getProperty("teamcity.version") != null;
  }

}
